import React, { useState, useEffect } from "react";
import axios from "axios";

const Home = () => {
		return (
			<div className="homeContainer">
				<form onSubmit={handleSubmit}>
					<label>
						<input type = "text"
						onChange = {handleChange}
						placeholder = "N° ou nom du Pokemon" 
						/>
					</label>
				</form>
				{pokemonData.map((data) => {
					return(
						<div className="searchBarPokemon"> 
						<img src={data.sprites["front_default"]} alt="Image du Pokemon" />
						<div className="divTable">				
							<div className="divTableRow">
							<div className="divTableCell">Type</div>
							<div className="divTableCell">{pokemonType}</div>
							</div>
							<div className="divTableRow">
							<div className="divTableCell">Taille</div>
							<div className="divTableCell">{""}
							{Math.round(data.height * 3.9)}
							</div>
							</div>
							<div className="divTableRow">
							<div className="divTableCell">Weight</div>
							<div className="divTableCell">{Math.round(data.weight / 4.3)} lbs</div>
							</div>
							</div>
							</div>
					)
				})}
				</div>
	);
};

export default Home;
